import{_ as r,c as t,o as a,a1 as i}from"./chunks/framework.DILC4Csi.js";const p=JSON.parse(`{"title":"Notes de publication : évolution des versions | Antigravity-Manager","description":"Découvrez la méthode d'évolution des versions d'Antigravity-Manager. Confirmez la version et vérifiez les mises à jour dans la page Settings, consultez les corrections et les rappels dans le Changelog README, et vérifiez la disponibilité après mise à niveau avec /healthz.","frontmatter":{"title":"Notes de publication : évolution des versions | Antigravity-Manager","sidebarTitle":"Comprendre les mises à jour en 3 minutes","subtitle":"Évolution des versions : basé sur le Changelog intégré dans le README","description":"Découvrez la méthode d'évolution des versions d'Antigravity-Manager. Confirmez la version et vérifiez les mises à jour dans la page Settings, consultez les corrections et les rappels dans le Changelog README, et vérifiez la disponibilité après mise à niveau avec /healthz.","tags":["changelog","release","upgrade","troubleshooting"],"prerequisite":["start-installation","start-proxy-and-first-client"],"order":1},"headers":[],"relativePath":"fr/lbjlaq/Antigravity-Manager/changelog/release-notes/index.md","filePath":"fr/lbjlaq/Antigravity-Manager/changelog/release-notes/index.md"}`),n={name:"fr/lbjlaq/Antigravity-Manager/changelog/release-notes/index.md"};function o(s,e,l,u,d,c){return a(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="evolution-des-versions-base-sur-le-changelog-integre-dans-le-readme" tabindex="-1">Évolution des versions : basé sur le Changelog intégré dans le README <a class="header-anchor" href="#evolution-des-versions-base-sur-le-changelog-integre-dans-le-readme" aria-label="Permalink to &quot;Évolution des versions : basé sur le Changelog intégré dans le README&quot;">​</a></h1><p>Vous vous préparez à mettre à niveau Antigravity Tools, et ce que vous craignez le plus n&#39;est pas « de ne pas avoir mis à jour », mais « de découvrir un changement de compatibilité après la mise à jour ». Cette page explique clairement comment lire le <strong>Changelog d&#39;Antigravity Tools (évolution des versions)</strong>, afin que vous puissiez juger avant la mise à niveau : cet impact de mise à jour vous affectera comment.</p><h2 id="ce-que-vous-pourrez-faire-apres-ce-chapitre" tabindex="-1">Ce que vous pourrez faire après ce chapitre <a class="header-anchor" href="#ce-que-vous-pourrez-faire-apres-ce-chapitre" aria-label="Permalink to &quot;Ce que vous pourrez faire après ce chapitre&quot;">​</a></h2><ul><li>Dans la page About des Settings, confirmer rapidement la version actuelle, vérifier les mises à jour et obtenir le lien de téléchargement</li><li>Dans le Changelog README, ne lire que les sections de version qui vous affectent (au lieu de parcourir du début à la fin)</li><li>Avant la mise à niveau, faire une chose : confirmer s&#39;il y a des rappels de « nécessitant de modifier manuellement la configuration/le mappage des modèles »</li><li>Après la mise à niveau, effectuer une vérification minimale (<code>/healthz</code>) pour confirmer que le proxy fonctionne toujours</li></ul><h2 id="qu-est-ce-que-le-changelog" tabindex="-1">Qu&#39;est-ce que le Changelog ? <a class="header-anchor" href="#qu-est-ce-que-le-changelog" aria-label="Permalink to &quot;Qu&#39;est-ce que le Changelog ?&quot;">​</a></h2><p><strong>Changelog</strong> est une liste enregistrant « ce qui a changé » par version. Antigravity Tools l&#39;écrit directement dans « Évolution des versions » du README, chaque version indiquant la date et les changements clés. Avant la mise à niveau, consulter le Changelog peut réduire la probabilité de rencontrer des changements de compatibilité ou des problèmes de régression.</p><h2 id="quand-utiliser-cette-page" tabindex="-1">Quand utiliser cette page <a class="header-anchor" href="#quand-utiliser-cette-page" aria-label="Permalink to &quot;Quand utiliser cette page&quot;">​</a></h2><ul><li>Vous préparez à mettre à niveau d&#39;une ancienne version vers une nouvelle version et souhaitez d&#39;abord confirmer les points de risque</li><li>Vous rencontrez un problème (comme 429/0 Token/Cloudflared) et souhaitez confirmer s&#39;il a été corrigé dans une version récente</li><li>Vous maintenez une version unifiée dans une équipe et devez fournir à vos collègues une méthode pour « lire les changements par version »</li></ul><h2 id="🎒-preparatifs-avant-de-commencer" tabindex="-1">🎒 Préparatifs avant de commencer <a class="header-anchor" href="#🎒-preparatifs-avant-de-commencer" aria-label="Permalink to &quot;🎒 Préparatifs avant de commencer&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Il est recommandé de préparer d&#39;abord le chemin de mise à niveau</p><p>Il y a de nombreuses façons d&#39;installer/mettre à niveau (brew, téléchargement manuel depuis Releases, mise à jour dans l&#39;application). Si vous n&#39;avez pas encore déterminé quelle voie utiliser, consultez d&#39;abord <strong><a href="/docs/opencodedocs/fr/lbjlaq/Antigravity-Manager/start/installation/">Installation et mise à niveau : meilleur chemin d&#39;installation de bureau (brew / releases)</a></strong>.</p></div><h2 id="suivez-moi" tabindex="-1">Suivez-moi <a class="header-anchor" href="#suivez-moi" aria-label="Permalink to &quot;Suivez-moi&quot;">​</a></h2><h3 id="etape-1-dans-la-page-about-confirmez-la-version-que-vous-utilisez-actuellement" tabindex="-1">Étape 1 : Dans la page About, confirmez la version que vous utilisez actuellement <a class="header-anchor" href="#etape-1-dans-la-page-about-confirmez-la-version-que-vous-utilisez-actuellement" aria-label="Permalink to &quot;Étape 1 : Dans la page About, confirmez la version que vous utilisez actuellement&quot;">​</a></h3><p><strong>Pourquoi</strong> Le Changelog est organisé par version. Vous devez d&#39;abord connaître votre version actuelle pour savoir « à partir d&#39;où commencer à lire ».</p><p>Chemin d&#39;accès : <strong>Settings</strong> → <strong>About</strong>.</p><p><strong>Ce que vous devriez voir</strong> : la zone d&#39;en-tête de la page affiche le nom de l&#39;application et le numéro de version (par exemple <code>v3.3.49</code>).</p><h3 id="etape-2-cliquez-sur-«-verifier-les-mises-a-jour-»-et-obtenez-la-derniere-version-et-le-lien-de-telechargement" tabindex="-1">Étape 2 : Cliquez sur « Vérifier les mises à jour » et obtenez la dernière version et le lien de téléchargement <a class="header-anchor" href="#etape-2-cliquez-sur-«-verifier-les-mises-a-jour-»-et-obtenez-la-derniere-version-et-le-lien-de-telechargement" aria-label="Permalink to &quot;Étape 2 : Cliquez sur « Vérifier les mises à jour » et obtenez la dernière version et le lien de téléchargement&quot;">​</a></h3><p><strong>Pourquoi</strong> Vous devez d&#39;abord savoir « quel est le numéro de la dernière version », puis aller dans le Changelog pour sélectionner les sections de version entre les deux.</p><p>Dans la page About, cliquez sur « Vérifier les mises à jour ».</p><p><strong>Ce que vous devriez voir</strong> :</p><ul><li>S&#39;il y a une mise à jour : invite « new version available » et un bouton de téléchargement apparaît (ouvre <code>download_url</code>)</li><li>Si c&#39;est déjà la dernière : invite « latest version »</li></ul><h3 id="etape-3-allez-dans-le-changelog-readme-et-ne-lisez-que-les-versions-que-vous-avez-sautees" tabindex="-1">Étape 3 : Allez dans le Changelog README et ne lisez que les versions que vous avez sautées <a class="header-anchor" href="#etape-3-allez-dans-le-changelog-readme-et-ne-lisez-que-les-versions-que-vous-avez-sautees" aria-label="Permalink to &quot;Étape 3 : Allez dans le Changelog README et ne lisez que les versions que vous avez sautées&quot;">​</a></h3><p><strong>Pourquoi</strong> Vous n&#39;avez besoin de vous soucier que des changements « entre votre version actuelle et la dernière version », les autres versions historiques peuvent être ignorées pour l&#39;instant.</p><p>Ouvrez le README, localisez <strong>« Évolution des versions (Changelog) »</strong>, et commencez à lire à partir de la dernière version vers le bas, jusqu&#39;à ce que vous voyiez votre version actuelle.</p><p><strong>Ce que vous devriez voir</strong> : les versions sont listées au format <code>vX.Y.Z (YYYY-MM-DD)</code>, et chaque version a des explications groupées (comme corrections principales/améliorations de fonctionnalités).</p><h3 id="etape-4-apres-la-mise-a-niveau-effectuez-une-verification-minimale" tabindex="-1">Étape 4 : Après la mise à niveau, effectuez une vérification minimale <a class="header-anchor" href="#etape-4-apres-la-mise-a-niveau-effectuez-une-verification-minimale" aria-label="Permalink to &quot;Étape 4 : Après la mise à niveau, effectuez une vérification minimale&quot;">​</a></h3><p><strong>Pourquoi</strong> La première chose après la mise à niveau n&#39;est pas « d&#39;exécuter des scénarios complexes », mais de confirmer d&#39;abord que le proxy peut démarrer normalement et peut être détecté par le client.</p><p>Suivez le processus de <strong><a href="/docs/opencodedocs/fr/lbjlaq/Antigravity-Manager/start/proxy-and-first-client/">Démarrer le proxy inverse local et connecter le premier client (/healthz + configuration SDK)</a></strong>, et vérifiez au moins une fois <code>GET /healthz</code>.</p><p><strong>Ce que vous devriez voir</strong> : <code>/healthz</code> renvoie un succès (pour confirmer que le service est disponible).</p><h2 id="resume-des-versions-recentes-extrait-du-readme" tabindex="-1">Résumé des versions récentes (extrait du README) <a class="header-anchor" href="#resume-des-versions-recentes-extrait-du-readme" aria-label="Permalink to &quot;Résumé des versions récentes (extrait du README)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Version</th><th>Date</th><th>Ce que vous devez surveiller</th></tr></thead><tbody><tr><td><code>v3.3.49</code></td><td>2026-01-22</td><td>Défense contre l&#39;interruption de réflexion et 0 Token ; suppression de <code>gemini-2.5-flash-lite</code> et rappel de remplacer manuellement le mappage personnalisé ; langage/thème et autres paramètres prennent effet immédiatement ; renforcement du tableau de bord de surveillance ; amélioration de la compatibilité OAuth</td></tr><tr><td><code>v3.3.48</code></td><td>2026-01-21</td><td>Processus en arrière-plan en mode silencieux sur Windows (correction du scintillement de la console)</td></tr><tr><td><code>v3.3.47</code></td><td>2026-01-21</td><td>Renforcement du mappage des paramètres de génération d&#39;images (<code>size</code>/<code>quality</code>) ; prise en charge du tunnel Cloudflared ; correction de l&#39;échec de démarrage dû aux conflits de fusion ; compression contextuelle progressive en trois couches</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Comment juger rapidement « cette mise à jour m&#39;affectera-t-elle »</p><p>Priorisez ces deux types de phrases :</p><ul><li><strong>Rappel utilisateur/vous devez modifier</strong> : comme nommer explicitement un modèle par défaut qui a été supprimé, exigeant que vous ajustiez manuellement le mappage personnalisé</li><li><strong>Correction principale/correction de compatibilité</strong> : comme 0 Token, 429, scintillement Windows, échec de démarrage, etc. problèmes « qui vous empêcheront de l&#39;utiliser »</li></ul></div><hr><h2 id="annexe-reference-du-code-source" tabindex="-1">Annexe : référence du code source <a class="header-anchor" href="#annexe-reference-du-code-source" aria-label="Permalink to &quot;Annexe : référence du code source&quot;">​</a></h2><details><summary><strong>Cliquez pour voir les emplacements du code source</strong></summary><blockquote><p>Dernière mise à jour : 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Contenu</th><th>Chemin du fichier</th><th>Numéros de ligne</th></tr></thead><tbody><tr><td>Changelog intégré README (évolution des versions)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/README.md#L324-L455" target="_blank" rel="noreferrer"><code>README.md</code></a></td><td>324-455</td></tr><tr><td>Page About affiche le numéro de version et le bouton « Vérifier les mises à jour »</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/Settings.tsx#L821-L954" target="_blank" rel="noreferrer"><code>src/pages/Settings.tsx</code></a></td><td>821-954</td></tr><tr><td>Structure de retour de la commande « Vérifier les mises à jour » de la page About</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/Settings.tsx#L187-L215" target="_blank" rel="noreferrer"><code>src/pages/Settings.tsx</code></a></td><td>187-215</td></tr><tr><td>Notification de mise à jour automatique (télécharger et redémarrer)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/components/UpdateNotification.tsx#L33-L96" target="_blank" rel="noreferrer"><code>src/components/UpdateNotification.tsx</code></a></td><td>33-96</td></tr><tr><td>Numéro de version actuel (métadonnées de construction)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/package.json#L1-L4" target="_blank" rel="noreferrer"><code>package.json</code></a></td><td>1-4</td></tr></tbody></table></details>',34)])])}const v=r(n,[["render",o]]);export{p as __pageData,v as default};
